import React, { useState, useEffect } from 'react';
import { useCalendar } from '../context/CalendarContext';

const TaskForm = ({ selectedDate, onClose }) => {
    const { addTask } = useCalendar();
    const [taskData, setTaskData] = useState({
        title: '',
        description: '',
        startDate: selectedDate,
        endDate: selectedDate,
        time: '',
        color: '#007bff'
    });

    const handleSubmit = async (e) => {
        e.preventDefault();
        e.stopPropagation(); // Prevent calendar collapse
        
        try {
            await addTask(taskData, true); // true for manual add
            onClose();
        } catch (error) {
            console.error('Failed to add task:', error);
            // Add error handling UI here
        }
    };

    return (
        <form onSubmit={handleSubmit} onClick={e => e.stopPropagation()} className="task-form">
            <input
                type="text"
                value={taskData.title}
                onChange={e => setTaskData(prev => ({ ...prev, title: e.target.value }))}
                placeholder="Task title"
                required
            />
            <textarea
                value={taskData.description}
                onChange={e => setTaskData(prev => ({ ...prev, description: e.target.value }))}
                placeholder="Description (optional)"
            />
            <input
                type="time"
                value={taskData.time}
                onChange={e => setTaskData(prev => ({ ...prev, time: e.target.value }))}
            />
            <input
                type="color"
                value={taskData.color}
                onChange={e => setTaskData(prev => ({ ...prev, color: e.target.value }))}
            />
            <div className="form-buttons">
                <button type="submit">Add Task</button>
                <button type="button" onClick={onClose}>Cancel</button>
            </div>
        </form>
    );
};

export default TaskForm;
